/**
 * ZohoEmbededAppSDK - Wrapper ligero para instancias Zoho EU
 * Detecta el SDK real inyectado por el CRM (inproductsdk) y lo usa si existe,
 * o inicializa el objeto ZOHO desde window.ZOHO si ya fue inyectado por el iframe del CRM.
 *
 * NOTA: En widgets hosted en Zoho (no externos), el CRM inyecta el objeto ZOHO
 * directamente en el contexto del iframe. Este script simplemente garantiza
 * que el objeto exista y expone los métodos necesarios con fallback.
 *
 * Basado en: https://github.com/zoho/embeddedApp-js-sdk v1.3
 */
(function (global) {
    "use strict";

    // Si el CRM ya inyectó ZOHO (caso habitual en hosted widgets), usarlo directamente
    if (global.ZOHO && global.ZOHO.embeddedApp && global.ZOHO.CRM) {
        return; // SDK ya disponible, nada que hacer
    }

    // --- Implementación mínima para widgets hosted en Zoho CRM ---
    var _listeners = {};
    var _initialized = false;
    var _resolveInit;
    var _initPromise = new Promise(function(resolve) { _resolveInit = resolve; });

    function postToParent(msg) {
        try { parent.postMessage(JSON.stringify(msg), '*'); } catch(e) {}
    }

    function ZohoEmbeddedApp() {}
    ZohoEmbeddedApp.prototype.on = function(event, callback) {
        _listeners[event] = callback;
    };
    ZohoEmbeddedApp.prototype.init = function() {
        if (!_initialized) {
            _initialized = true;
            postToParent({ action: 'init', service: 'CRM' });
        }
        return _initPromise;
    };

    // Escuchar mensajes del CRM padre
    global.addEventListener('message', function(e) {
        try {
            var data = (typeof e.data === 'string') ? JSON.parse(e.data) : e.data;
            if (!data) return;

            if (data.action === 'init' || data.type === 'init') {
                _resolveInit(data);
            }
            if (data.action === 'PageLoad' || (data.type === 'event' && data.name === 'PageLoad')) {
                var payload = data.data || data.payload || data;
                if (_listeners['PageLoad']) _listeners['PageLoad'](payload);
            }
        } catch(err) {}
    });

    // --- API helpers ---
    function makeApiRequest(config) {
        return new Promise(function(resolve, reject) {
            var msgId = 'req_' + Date.now() + '_' + Math.random();
            var handler = function(e) {
                try {
                    var data = (typeof e.data === 'string') ? JSON.parse(e.data) : e.data;
                    if (data && data.requestId === msgId) {
                        global.removeEventListener('message', handler);
                        if (data.error) reject(data.error);
                        else resolve(data.response || data.data || data);
                    }
                } catch(err) {}
            };
            global.addEventListener('message', handler);
            postToParent({ action: 'apiRequest', requestId: msgId, config: config });
            setTimeout(function() {
                global.removeEventListener('message', handler);
                reject({ message: 'Request timeout', config: config });
            }, 15000);
        });
    }

    var ZOHO = {
        embeddedApp: new ZohoEmbeddedApp(),
        CRM: {
            API: {
                getRecord: function(config) {
                    return makeApiRequest({ type: 'getRecord', params: config });
                },
                searchRecord: function(config) {
                    return makeApiRequest({ type: 'searchRecord', params: config });
                }
            },
            HTTP: {
                post: function(config) {
                    return makeApiRequest({ type: 'http_post', params: config });
                },
                get: function(config) {
                    return makeApiRequest({ type: 'http_get', params: config });
                }
            },
            CONFIG: {
                getCurrentUser: function() {
                    return makeApiRequest({ type: 'getCurrentUser' });
                }
            },
            UI: {
                Record: {
                    open: function(config) { postToParent({ action: 'openRecord', config: config }); },
                    create: function(config) { postToParent({ action: 'createRecord', config: config }); }
                }
            }
        }
    };

    global.ZOHO = ZOHO;

}(window));
